#include <bits/stdc++.h> 
using namespace std;
const int N=100005;
int n,s[N],b[N],c[N];
struct node
{
	int s,num;
	bool operator<(const node other) const
	{
		return num>other.num;
	}
} a[N];
int main()
{
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i].s;
		a[i].s*=2;
	}
	for(int i=1;i<=n;i++)
	{
		cin>>a[i].num;
	}
	sort(a+1,a+1+n);
	for(int i=1;i<=n;i++)
	{
		s[i]=s[i-1]+a[i].num;
		b[i]=max(b[i-1],a[i].s);
	}
	for(int i=n;i>=1;i--)
	{
		c[i]=max(c[i+1],a[i].s+a[i].num);
	}
	for(int i=1;i<=n;i++)
	{
		cout<<max(s[i]+b[i],s[i-1]+c[i])<<'\n';
	}
	return 0;
}
